const { randomUUID } = require('node:crypto');
const projects = require('../projects/service').getAll();
const members = {};

function create(projectId, memberData) {
  const project = projects.find(p => p.id === projectId);
  if (!project) {
    throw { code: 'not_found', message: 'Project not found' };
  }
  if (members[projectId] && members[projectId].some(m => m.userId === memberData.userId)) {
    throw { code: 'duplicate', message: 'Member already exists in project' };
  }
  const memberId = randomUUID();
  if (!members[projectId]) {
    members[projectId] = [];
  }
  members[projectId].push({ ...memberData, id: memberId });
  return members[projectId][members[projectId].length - 1];
}

function getAll(projectId) {
  const projectMembers = members[projectId] || [];
  return projectMembers;
}

module.exports = { create, getAll };

const router = require('express').Router({ mergeParams: true });
const tasksService = require('./service');
const { sendError } = require('../../lib/errors');
router.get('/', async (req, res) => {
  const status = typeof req.query?.status === 'string' ? req.query.status : undefined;
  const tasks = await tasksService.getAllTasks(req.params.projectId, status);
  return res.json({ tasks });
});
router.post('/', async (req, res) => {
  const title = String(req.body?.title || "").trim();
  if (!title) return sendError(res, 400, 'BAD_REQUEST', 'Task title is required');
  const task = await tasksService.createTask(req.params.projectId, title);
  return res.status(201).json({ task });
});
router.patch('/:taskId', async (req, res) => {
  const status = String(req.body?.status || '').trim();
  if (status !== 'todo' && status !== 'done') return sendError(res, 400, 'INVALID_STATUS', 'Status must be todo or done');
  const task = await tasksService.updateTaskStatus(req.params.projectId, req.params.taskId, status);
  if (!task) return sendError(res, 404, 'TASK_NOT_FOUND', 'Task not found');
  return res.json({ task });
});
module.exports = router;

const { randomUUID } = require('node:crypto');
const projects = require('../projects/service').getAll();
const tasks = {};

function create(projectId, taskData) {
  const project = projects.find(p => p.id === projectId);
  if (!project) {
    throw { code: 'not_found', message: 'Project not found' };
  }
  const taskId = randomUUID();
  if (!tasks[projectId]) {
    tasks[projectId] = [];
  }
  tasks[projectId].push({ ...taskData, id: taskId, status: 'pending' });
  return tasks[projectId][tasks[projectId].length - 1];
}

function getAll(projectId, status) {
  const projectTasks = tasks[projectId] || [];
  if (status) {
    return projectTasks.filter(task => task.status === status);
  }
  return projectTasks;
}

function update(projectId, taskId, taskData) {
  const projectTasks = tasks[projectId];
  if (!projectTasks) {
    throw { code: 'not_found', message: 'Project not found' };
  }
  const taskIndex = projectTasks.findIndex(task => task.id === taskId);
  if (taskIndex === -1) {
    throw { code: 'not_found', message: 'Task not found' };
  }
  tasks[projectId][taskIndex] = { ...projectTasks[taskIndex], ...taskData };
  return tasks[projectId][taskIndex];
}

module.exports = { create, getAll, update };
module.exports.createTask = module.exports.create;
